function createDataUpdater() {
  const cache = new Map(); // id -> [last 5 results]
  let renderPromise = Promise.resolve();
  let renderScheduled = false;

  const updateCache = (id, data) => {
    const history = cache.get(id) || [];
    history.push(data);
    if (history.length > 5) history.shift();
    cache.set(id, history);
  };

  const render = () => {
    renderScheduled = false;
    // Apply cache data to UI
  };

  const scheduleRender = () => {
    if (!renderScheduled) {
      renderScheduled = true;
      requestAnimationFrame(render);
    }
  };

  return {
    processBatch: (batch) => {
      renderPromise = renderPromise.then(() => {
        batch.forEach(item => updateCache(item.id, item.data));
        scheduleRender();
      });
    }
  };
}
