// budget gate per route
const ROUTE_BUDGETS = { home: 280000, dashboard: 320000 };
let usedByRoute = {};
function safeLoad(route, path, sizeEstimate) {
  const budget = ROUTE_BUDGETS[route] ?? 300000;
  const used = usedByRoute[route] || 0;
  if (used + sizeEstimate > budget) {
    return import(`./${path}.lite.js`);
  }
  usedByRoute[route] = used + sizeEstimate;
  return import(`./${path}.js`);
}
