const bucketizeBySecond = createSelector(
  [selectEvents],
  (events) => {
    const buckets = [];
    let current = [];
    let currentSecond = null;
    for (const e of events) {
      const t = Math.floor(e.ts / 1000) * 1000;
      if (currentSecond !== t) {
        if (current.length) buckets.push(current);
        current = [e];
        currentSecond = t;
